+/// Apply shift mapping for US keyboard layout
+fn applyShiftMapping(char: u8) u8 {
+    if (char >= 'a' and char <= 'z') return char - 32; // A-Z
+    return switch (char) {
+        '1' => '!', '2' => '@', '3' => '#', '4' => '$', '5' => '%',
+        '6' => '^', '7' => '&', '8' => '*', '9' => '(', '0' => ')',
+        '-' => '_', '=' => '+', '[' => '{', ']' => '}', '\\' => '|',
+        ';' => ':', '\'' => '"', ',' => '<', '.' => '>', '/' => '?', '`' => '~',
+        else => char,
+    };
+}
+
 /// Send a character to the browser with modifiers (for Cmd+A, Ctrl+C, etc.)
